CREATE TABLE IF NOT EXISTS pipeline_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), pipeline_type text NOT NULL CHECK (pipeline_type IN ('collect', 'process', 'daily_push', 'weekly_summary')), status text NOT NULL DEFAULT 'running' CHECK (status IN ('running', 'completed', 'failed', 'cancelled')), started_at timestamptz NOT NULL DEFAULT now(), completed_at timestamptz, logs jsonb DEFAULT '[]', stats jsonb, error text);
